// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract AsmProbe {
    uint256 public value;

    function set(uint256 newValue) public {
        assembly {
            if gt(newValue, 100) {
                revert(0, 0)
            }
            sstore(1, newValue)
        }
        value = newValue;
    }
}
